sp_page.css:
/* !!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!
      Container 2 Row has CSS selector row auto added to our ask of fill-section flex-row
        and we have to override the row style else we get a scrollbar at the bottom of the page
        see div.sp-row-content.fill-section.flex-row.row below
   !!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!! */
div.sp-row-content.fill-section.flex-row.row,
div.sp-row-content.fill-section.flexbox.row {
  margin-left: 0;
  margin-right: 0;
}

/* 2.8 | 2022-06-17 | mmcc | DFCT0010888; flex sp-widget for Tasker Data Table start */
.v1fe908a64fc71300d236eb118110c78a {
  display: flex;
  flex-grow: 1;
  justify-content: center;
}
/* 2.8 | 2022-06-17 | mmcc | DFCT0010888; flex sp-widget for Tasker Data Table end */


/************************************************************
START - new CSS to add KB widget to page 
2.8 | 2022-08-03 | raj  | new CSS to add KB widget to page 
************************************************************/
/* This is the widget control on the page*/
.va47ea1cb0b9432004ce28ffe15673a5b {
  display: flex;
  flex-grow: 1;
  justify-content: center;
	overflow:auto;
}

/* this is inside the KB Article widget - Outermost wrapper */
.va47ea1cb0b9432004ce28ffe15673a5b .kb-article-wrapper {
  display: flex;
  flex-grow: 1;
  justify-content: center;
	overflow:auto;
}
/* this is inside the KB Article widget - Panel for both Desktop */
.va47ea1cb0b9432004ce28ffe15673a5b .kb-desktop.panel {
  display: flex;
  flex-direction: column;
  flex-grow: 1;
	overflow:auto;
}
/* this is inside the KB Article widget - Panel for mobile */
.va47ea1cb0b9432004ce28ffe15673a5b .panel .panel-default {
  display: flex;
  flex-direction: column;
  flex-grow: 1;
	overflow:auto;
}
/* this is inside the KB Article widget - Panel Header, no overflow */
.va47ea1cb0b9432004ce28ffe15673a5b .kb-panel-heading {
  display: flex;
  flex-direction: column;
  flex-grow: 1;
} 
/* this is inside the KB Article widget - Panel Body for desktop, no overflow */
.va47ea1cb0b9432004ce28ffe15673a5b .kb-desktop-wrapper .panel-body {
  display: flex;
  flex-direction: column;
  overflow:auto;
  flex-grow: 1;
} 

/* this is inside the KB Article widget - Panel Body for mobile, no overflow */
.va47ea1cb0b9432004ce28ffe15673a5b .kb-mobile-wrapper .panel-body {
  display: flex;
  flex-direction: column;
  overflow:auto;
  flex-grow: 1;
} 

/************************************************************
END - new CSS to add KB widget to page 
************************************************************/
